public static string Camelize(this string input)
{
    var matches = WordPartsRegex().Matches(input);
    if (matches.Count == 0)
    {
        return input;
    }

    var sb = new StringBuilder(input.Length);

    // First word: lowercase initial letter
    var first = matches[0].Value;
    sb.Append(char.ToLowerInvariant(first[0]));
    sb.Append(first.AsSpan(1));

    // Remaining words: uppercase initial letter
    for (var i = 1; i < matches.Count; i++)
    {
        var word = matches[i].Value;
        sb.Append(char.ToUpperInvariant(word[0]));
        sb.Append(word.AsSpan(1));
    }

    return sb.ToString();
}

