public InflectionRule(string pattern, string replacement)
{
    // Interpreted regex avoids the expensive JIT compilation cost per instance.
    // For short strings and many rules, interpreted is faster overall.
    _regex = new Regex(pattern, RegexOptions.IgnoreCase);
    _replacement = replacement;
}

/// <summary>
/// Attempts to apply this rule to the given word.
/// </summary>
/// <param name="word">The word to transform.</param>
/// <returns>The transformed word if the pattern matches; otherwise, null.</returns>
public string? Apply(string word)
{
    var result = _regex.Replace(word, _replacement);
    if (ReferenceEquals(result, word) || result == word)
    {
        return null;
    }

    return result;
}

